import{c as t,Q as a,j as i,m as o}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Use Cases for LDK","description":"","frontmatter":{},"headers":[],"relativePath":"introduction/use-cases.md","filePath":"introduction/use-cases.md","lastUpdated":1782481933000}'),n={name:"introduction/use-cases.md"};function s(r,e,c,l,h,d){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="use-cases-for-ldk" tabindex="-1">Use Cases for LDK <a class="header-anchor" href="#use-cases-for-ldk" aria-label="Permalink to &quot;Use Cases for LDK&quot;">​</a></h1><p>The standard Lightning use case is running a standalone node on one&#39;s laptop. Here&#39;s some other use cases that LDK supports.</p><h2 id="mobile-devices" tabindex="-1">Mobile Devices <a class="header-anchor" href="#mobile-devices" aria-label="Permalink to &quot;Mobile Devices&quot;">​</a></h2><p>Mobile devices with Lightning have unique requirements often not well served by today&#39;s Lightning ecosystem. Not only do they need to operate with minimal footprint, they also have intermittent data access and cannot shutdown safely. More importantly, many existing wallets already have business logic to handle blockchain data, keys, and storage, and do not wish to duplicate much of that logic to integrate Lightning (at worst fetching the blockchain twice). LDK offers a flexible API to allow users to integrate Lightning with their own keys, blockchain data, and storage. To allow full flexibility in footprint, the API supports routing data being fetched via the Lightning P2P protocol, an external service, or routes can be calculated off-device. It also provides cross-platform compatibility for free, allowing synchronization of Lightning state across devices and, as long as there is protection from simultaneous updates, users to access their wallet on any device. See the <a href="./architecture">architecture</a> page for more details on the interfaces LDK provides for integration.</p><h2 id="hsms-hardware-security-modules" tabindex="-1">HSMs (Hardware Security Modules) <a class="header-anchor" href="#hsms-hardware-security-modules" aria-label="Permalink to &quot;HSMs (Hardware Security Modules)&quot;">​</a></h2><p>LDK Supports various HSM configurations. In conjunction with the <a href="https://vls.tech/" target="_blank" rel="noreferrer">Validating Lightning Signer</a>project, an external HSM can be used to verify most protocol details about states before signing, ensuring host compromise cannot steal funds by broadcasting revoked states. For nodes seeking a higher level of assurance, the entire LDK channel state machine can be run on an offline device, communicating with the outside world via a proxy host which maintains TCP connections with peers. Such a configuration ensures all details of the Lightning protocol are enforced without consideration of host compromise.</p><h2 id="production-lightning-nodes" tabindex="-1">Production Lightning Nodes <a class="header-anchor" href="#production-lightning-nodes" aria-label="Permalink to &quot;Production Lightning Nodes&quot;">​</a></h2><p>Many large Bitcoin transactors have large amounts of custom-built infrastructure for interacting with the Bitcoin blockchain. Such tight integration with business logic may be difficult with existing Lightning implementations focusing on standalone operation. For such transactors, LDK offers the possibility of integrating a library in their native runtime, storing and handling Lightning data and events in the same way they do blockchain events.</p>',8)])])}const f=t(n,[["render",s]]);export{g as __pageData,f as default};
